}

function parseTimeMySQL(str) {
    if (!str) return null;

    // Asegura formato HH:MM:SS
    const parts = String(str).split(":");
    const h = parts[0]?.padStart(2, '0') ?? "00";
    const m = parts[1]?.padStart(2, '0') ?? "00";
    const s = parts[2]?.padStart(2, '0') ?? "00";

    return `${h}:${m}:${s}`;
}

